(function () {
  function el(tag, className) {
    const node = document.createElement(tag);
    if (className) node.className = className;
    return node;
  }

  function setupCanvas(canvas) {
    const rect = canvas.getBoundingClientRect();
    const dpr = window.devicePixelRatio || 1;
    canvas.width = Math.max(1, Math.floor(rect.width * dpr));
    canvas.height = Math.max(1, Math.floor(rect.height * dpr));
    const ctx = canvas.getContext('2d');
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
    return ctx;
  }

  function drawCenteredText(ctx, text) {
    ctx.textAlign = 'center';
    ctx.fillText(text, 0, 0);
  }

  const DEFAULT_FONT = "12px 'DM Sans', system-ui, sans-serif";

  class Chart {
    constructor(canvas, config) {
      this.canvas = canvas;
      this.config = config || {};
      this.render();
    }

    render() {
      const type = this.config.type;
      const data = this.config.data || {};
      const options = this.config.options || {};
      const parent = this.canvas.parentElement;
      if (!parent) return;
      parent.querySelectorAll('.chartjs-legend').forEach((node) => node.remove());
      const ctx = setupCanvas(this.canvas);
      ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);
      if (type === 'doughnut') this.drawDoughnut(ctx, data, options, parent);
      if (type === 'bar') this.drawBar(ctx, data, options);
    }

    drawDoughnut(ctx, data, options, parent) {
      const dataset = (data.datasets && data.datasets[0]) || {};
      const values = dataset.data || [];
      const labels = data.labels || [];
      const colors = dataset.backgroundColor || [];
      const radius = Math.min(this.canvas.clientWidth, this.canvas.clientHeight) * 0.3;
      const cx = this.canvas.clientWidth / 2;
      const cy = this.canvas.clientHeight / 2;
      const total = values.reduce((acc, v) => acc + Number(v || 0), 0) || 1;
      let angle = -Math.PI / 2;
      values.forEach((v, idx) => {
        const slice = (Number(v || 0) / total) * Math.PI * 2;
        ctx.beginPath();
        ctx.moveTo(cx, cy);
        ctx.arc(cx, cy, radius, angle, angle + slice);
        ctx.closePath();
        ctx.fillStyle = colors[idx] || '#1f4b5f';
        ctx.fill();
        angle += slice;
      });
      ctx.beginPath();
      ctx.arc(cx, cy, radius * 0.55, 0, Math.PI * 2);
      ctx.fillStyle = getComputedStyle(document.documentElement).getPropertyValue('--panel') || '#16202b';
      ctx.fill();

      const legend = el('ul', 'chartjs-legend');
      legend.style.listStyle = 'none';
      legend.style.padding = '12px 0 0';
      legend.style.margin = '0';
      legend.style.display = 'grid';
      legend.style.gap = '6px';
      const legendColor =
        (options.plugins && options.plugins.legend && options.plugins.legend.labels && options.plugins.legend.labels.color) ||
        'inherit';
      labels.forEach((label, idx) => {
        const item = el('li');
        item.style.display = 'flex';
        item.style.alignItems = 'center';
        item.style.gap = '8px';
        item.style.color = legendColor;
        const swatch = el('span');
        swatch.style.width = '10px';
        swatch.style.height = '10px';
        swatch.style.borderRadius = '50%';
        swatch.style.display = 'inline-block';
        swatch.style.background = colors[idx] || '#1f4b5f';
        const text = el('span');
        text.textContent = label;
        item.appendChild(swatch);
        item.appendChild(text);
        legend.appendChild(item);
      });
      parent.appendChild(legend);
    }

    drawBar(ctx, data, options) {
      const dataset = (data.datasets && data.datasets[0]) || {};
      const values = (dataset.data || []).map(Number);
      const xLabels = data.labels || [];
      const width = this.canvas.clientWidth;
      const height = this.canvas.clientHeight;
      const max = Math.max(...values, 1);

      const font = (options.font && options.font.canvas) || DEFAULT_FONT;
      const yTicks = (options.scales && options.scales.y && options.scales.y.ticks) || {};
      const yCallback =
        typeof yTicks.callback === 'function' ? yTicks.callback : (v) => String(v.toFixed(0));
      const yLabels = [];
      for (let i = 0; i <= 4; i += 1) yLabels.push(String(yCallback((max * i) / 4)));

      ctx.font = font;
      let maxLabelWidth = 0;
      for (const label of yLabels) {
        const w = ctx.measureText(label).width;
        if (w > maxLabelWidth) maxLabelWidth = w;
      }

      const padLeft = Math.max(40, Math.min(120, Math.ceil(maxLabelWidth) + 14));
      const padRight = 20;
      const padTop = 20;
      const padBottom = 40;
      const chartWidth = width - padLeft - padRight;
      const chartBottom = height - padBottom;
      const slot = chartWidth / Math.max(1, values.length);

      const xTicks = (options.scales && options.scales.x && options.scales.x.ticks) || {};
      const xGrid = (options.scales && options.scales.x && options.scales.x.grid) || {};
      const yGrid = (options.scales && options.scales.y && options.scales.y.grid) || {};
      const tickColor = xTicks.color || '#eef1f5';
      const yTickColor = yTicks.color || tickColor;
      const xGridColor = xGrid.color || '#233141';
      const yGridColor = yGrid.color || xGridColor;

      ctx.strokeStyle = xGridColor;
      ctx.fillStyle = tickColor;
      ctx.beginPath();
      ctx.moveTo(padLeft, padTop);
      ctx.lineTo(padLeft, chartBottom);
      ctx.lineTo(padLeft + chartWidth, chartBottom);
      ctx.stroke();

      values.forEach((value, idx) => {
        const drawHeight = (value / max) * (chartBottom - padTop);
        const barX = padLeft + idx * slot + slot * 0.15;
        const barWidth = slot * 0.7;
        ctx.fillStyle = dataset.backgroundColor || '#1f4b5f';
        ctx.fillRect(barX, chartBottom - drawHeight, barWidth, drawHeight);

        ctx.save();
        ctx.translate(barX + barWidth / 2, chartBottom + 14);
        ctx.fillStyle = tickColor;
        ctx.font = font;
        drawCenteredText(ctx, String(xLabels[idx] || ''));
        ctx.restore();
      });

      ctx.font = font;
      ctx.textAlign = 'right';
      for (let i = 0; i <= 4; i += 1) {
        const tickValue = (max * i) / 4;
        const y = chartBottom - (chartBottom - padTop) * (i / 4);
        ctx.fillStyle = yTickColor;
        ctx.fillText(yLabels[i] || String(tickValue.toFixed(0)), padLeft - 8, y + 4);
        ctx.strokeStyle = yGridColor;
        ctx.beginPath();
        ctx.moveTo(padLeft, y);
        ctx.lineTo(padLeft + chartWidth, y);
        ctx.stroke();
      }
    }
  }

  window.Chart = Chart;
})();
